                sortSteps.push({
                    type: 'swap',
                    arr: [...arr],
                    i: 0,
                    j: i,
                    message: `Moving root (max element) to position ${i}`
                });
                [arr[0], arr[i]] = [arr[i], arr[0]];
                sortedIndices.push(i);

                sortSteps.push({
                    type: 'heapify',
                    arr: [...arr],
                    n: i,
                    i: 0,
                    message: `Heapifying the reduced heap of size ${i}`
                });
                heapifyForSteps(arr, i, 0);
            }

            sortedIndices.push(0);
            sortSteps.push({
                type: 'complete',
                arr: [...arr],
                message: 'Sorting complete!'
            });
        }

